from PIL import Image
im = Image.open('chess_board.png').convert('RGB')
W,H=im.size; sq=W//8; px=im.load()
files='abcdefgh'
def render(sqname,N=40,mode='@'):
    c=files.index(sqname[0]); r=8-int(sqname[1])
    x0,y0=c*sq,r*sq
    out=[]
    for iy in range(N):
        line=''
        for ix in range(N):
            xx=x0+int((ix+0.5)*sq/N); yy=y0+int((iy+0.5)*sq/N)
            p=px[xx,yy]
            lum=0.299*p[0]+0.587*p[1]+0.114*p[2]
            if mode=='@':
                line+='@' if lum<70 else '.'
            else:
                line+='#' if lum>230 else '.'
        out.append(line.rstrip())
    return out
for s in ['c8','g5']:
    print('==== '+s+' (black) ====')
    for l in render(s): print(l)
print('==== e1 (white king ref) ====')
